:root {
  --animation-dimension: 100px;
  --animation-start-color: #71e171;
  --animation-midway-color: #67d067;
  --animation-finish-color: #59b259;
}

.checkmark {
  width: var(--animation-dimension);
  height: var(--animation-dimension);
  border-radius: 50%;
  display: block;
  stroke-width: 5;
  stroke: #ffffff;
  stroke-miterlimit: 10;
  box-shadow: 0px 0px 10px rgba(0, 0, 0, 0.1);
  animation: fill 0.4s ease-in-out 0.4s forwards,
    scale 0.3s ease-in-out 0.9s both;
}

.checkmarkCircle {
  stroke-dasharray: 166;
  stroke-dashoffset: 166;
  stroke-width: 5;
  stroke-miterlimit: 10;
  stroke: var(--animation-finish-color);
  fill: none;
  animation: stroke 0.6s cubic-bezier(0.65, 0, 0.45, 1) forwards,
    colorChange 1.2s ease-in-out forwards;
}

.checkmarkCheck {
  transform-origin: 50% 50%;
  stroke-dasharray: 48;
  stroke-dashoffset: 48;
  animation: stroke 0.3s cubic-bezier(0.65, 0, 0.45, 1) 0.8s forwards,
    colorChange 0.6s ease-in-out 0.8s forwards;
}

@keyframes colorChange {
  0% {
    stroke: var(--animation-start-color);
  }
  50% {
    stroke: var(--animation-midway-color);
  } 
  100% {
    stroke: var(--animation-finish-color);
  }
}

@keyframes stroke {
  100% {
    stroke-dashoffset: 0;
  }
}
@keyframes scale {
  0%,
  100% {
    transform: none;
  }
  50% {
    transform: scale3d(1.1, 1.1, 1);
  }
  70% {
    transform: scale3d(0.98, 0.98, 1);
  }
  85% {
    transform: scale3d(1.02, 1.02, 1);
  }
}
@keyframes fill {
  100% {
    box-shadow: inset 0px 0px 0px 0px var(--animation-finish-color);
  }
}

customScript.value:
const setFieldFocus = (id) => {
    const element = document.getElementById(id);
    if (element) {
        element.focus();
    }
}

const makePasswordToggle = (id) => {
    let container = document.getElementById(id);

    if (container) {
        let password = container.getElementsByTagName("input")[0];
        let toggler = document.createElement("button");
        toggler.setAttribute("type", "button");
        toggler.setAttribute("aria-label", "Show/Hide Password");
        toggler.className = "btn mdi mdi-eye-off-outline position-absolute end-0 top-50 translate-middle-y";
        container.appendChild(toggler);

        function showHidePassword() {
            if (password.type == "password") {
                password.setAttribute("type", "text");
                toggler.classList.add("mdi-eye-outline");
                toggler.classList.remove("mdi-eye-off-outline");
            } else {
                toggler.classList.add("mdi-eye-off-outline");
                toggler.classList.remove("mdi-eye-outline");
                password.setAttribute("type", "password");
            }
            password.focus();
        };

        toggler.addEventListener("click", showHidePassword);
    }
}

const start = () => {
    makePasswordToggle("passwordContainer");
    setFieldFocus("email")
}

if (document.readyState === "loading") {
    // Loading hasn't finished yet
    document.addEventListener("DOMContentLoaded", start);
} else {
    // `DOMContentLoaded` has already fired
    start();
}

